class Solution {
public:
    vector<int> splitIntoFibonacci(string num) {
        int n = num.size();
        for (int i = 1; i <= n / 2; ++i) {
            if (num[0] == '0' && i > 1) break;
            for (int j = 1; j <= (n - i) / 2; ++j) {
                string a = num.substr(0, i);
                string b = num.substr(i, j);
                if (num[0] == '0' && i > 1) break;
                if (b[0] == '0' && j > 1) continue;
                long long A = stoll(a);
                long long B = stoll(b);
                string remaining = num.substr(i + j);
                while (remaining.size() > 0) {
                    long long C = A + B;
                    string c = to_string(C);
                    if (remaining.find(c) != 0) return {};
                    remaining = remaining.substr(c.size());
                    A = B; B = C;
                }
                return {A, B};
            }
        }
        return {};
    }
};
